<?php declare(strict_types=1);namespace App\Services;final class StreamingProfileService{public function selectForPlaylist(array $metadata,?string $requested=null,?array $server=null,?array $health=null):array{if(!$metadata)throw new \InvalidArgumentException('Playlist metadata is required.');$config=config('profiles');$highest=$metadata[0];foreach($metadata as$item)if($item['height']>$highest['height']||($item['height']===$highest['height']&&$item['fps']>$highest['fps']))$highest=$item;$name=$requested?:$config['default'];if($name==='auto'){$name=$this->serverProfile($server);if(($health['status']??'healthy')==='critical')$name='micro';if($highest['height']>1080||($highest['height']>=1080&&$highest['fps']>30))$name='standard';}$profile=$config['profiles'][$name]??$config['profiles']['standard'];return array_merge(['name'=>$name,'source_metadata'=>$metadata,'highest_input'=>$highest],$profile);}private function serverProfile(?array $server):string{$name=$server['name']??null;return in_array($name,['micro','standard','high','ultra'],true)?$name:'standard';}}
